// Smart cadence: 1 s ONLY when (reception mode AND any modal is open), else
// 30 s (so the header clock still tracks the wall-clock minute). This avoids
// waking up once a second for a display that's mostly showing the same value.
function scheduleSystemClock(forceSlow?: boolean) {
  if (systemClockInterval != null) {
    clearInterval(systemClockInterval);
    systemClockInterval = null;
  }
  const fast = !forceSlow && isReceptionMode.value && isTableModalOpen.value
  systemClockInterval = setInterval(updateSystemClock, fast ? 1000 : 30_000) as unknown as number;
}

async function loadTables() {
  const { branchId } = useAuth();
  const bid = branchId.value;
  if (!bid) return;

  const { data: tablesData } = await supabase
    .from('tables')
    .select('id, code, capacity, status, metadata')
    .eq('branch_id', bid)
    .order('code', { ascending: true });

  if (tablesData && tablesData.length > 0) {
    const byZone = new Map<string, { name: string; tables: TableInfo[] }>();
    for (const t of tablesData as any[]) {
      const zoneName = t.metadata?.zone || 'Main';
      if (!byZone.has(zoneName)) {
        byZone.set(zoneName, { name: zoneName, tables: [] });
      }

      const uiStatus: TableInfo['status'] =
        t.status === 'available' ? 'Available'
        : t.status === 'reserved' ? 'Reserved'
        : t.status === 'occupied' ? 'Serving'
        : t.status === 'maintenance' ? 'Maintenance'
        : 'Available';

      byZone.get(zoneName)!.tables.push({
        id: t.id,
        code: t.code,
        status: uiStatus,
        capacity: t.capacity,
        metadata: t.metadata || {}
      });
    }

    areas.value = Array.from(byZone.values())
      .sort((a, b) => a.name.localeCompare(b.name, 'vi'))
      .map<AreaInfo>((z) => ({
        name: z.name,
        description: z.name,
        tables: z.tables,
      }));
  }
}

